  1→package dashboard
  2→
  3→import (
  4→	"fmt"
  5→	"strings"
  6→	"time"
  7→
  8→	"github.com/charmbracelet/lipgloss"
  9→
 10→	"github.com/jcleira/entire-local/pkg/checkpoint"
 11→)
 12→
 13→func renderCheckpointList(summaries []checkpoint.CheckpointSummary, cursor, height int, filter string, width int) string {
 14→	filtered := filterSummaries(summaries, filter)
 15→
 16→	var sb strings.Builder
 17→
 18→	header := headerStyle.Render("Checkpoints")
 19→	if filter != "" {
 20→		header += " " + filterStyle.Render("[/"+filter+"]")
 21→	}
 22→	header += dimStyle.Render(fmt.Sprintf(" (%d)", len(filtered)))
 23→	sb.WriteString(header)
 24→	sb.WriteString("\n")
 25→
 26→	if len(filtered) == 0 {
 27→		sb.WriteString(dimStyle.Render("  No checkpoints found"))
 28→		return sb.String()
 29→	}
 30→
 31→	visibleHeight := (height - 2) / 4
 32→	if visibleHeight < 1 {
 33→		visibleHeight = 1
 34→	}
 35→
 36→	start := 0
 37→	if cursor >= visibleHeight {
 38→		start = cursor - visibleHeight + 1
 39→	}
 40→	end := start + visibleHeight
 41→	if end > len(filtered) {
 42→		end = len(filtered)
 43→	}
 44→
 45→	contentWidth := width - 4
 46→	if contentWidth < 40 {
 47→		contentWidth = 40
 48→	}
 49→
 50→	for i := start; i < end; i++ {
 51→		s := filtered[i]
 52→		block := renderCheckpointBlock(s, contentWidth)
 53→
 54→		if i == cursor {
 55→			sb.WriteString(selectedRowStyle.Render(block))
 56→		} else {
 57→			sb.WriteString(normalRowStyle.Render(block))
 58→		}
 59→		sb.WriteString("\n")
 60→	}
 61→
 62→	if len(filtered) > visibleHeight {
 63→		sb.WriteString(scrollIndicatorStyle.Render(fmt.Sprintf("  (%d/%d)", cursor+1, len(filtered))))
 64→	}
 65→
 66→	return sb.String()
 67→}
 68→
 69→func renderCheckpointBlock(s checkpoint.CheckpointSummary, width int) string {
 70→	sep := dimStyle.Render("  ·  ")
 71→
 72→	title := s.CommitMessage
 73→	if title == "" {
 74→		title = cleanPromptExcerpt(s.Prompt)
 75→	}
 76→	if title == "" {
 77→		title = s.Context
 78→	}
 79→	if title == "" {
 80→		title = s.Branch
 81→	}
 82→	if idx := strings.IndexByte(title, '\n'); idx >= 0 {
 83→		title = title[:idx]
 84→	}
 85→	title = strings.TrimSpace(title)
 86→	if len(title) > width {
 87→		title = title[:width-1] + "…"
 88→	}
 89→	line1 := lipgloss.NewStyle().Bold(true).Render(title)
 90→
 91→	subtitle := ""
 92→	if s.CommitMessage != "" {
 93→		excerpt := cleanPromptExcerpt(s.Prompt)
 94→		if excerpt != "" && excerpt != title {
 95→			if len(excerpt) > width {
 96→				excerpt = excerpt[:width-1] + "…"
 97→			}
 98→			subtitle = dimStyle.Render(excerpt)
 99→		}
100→	}
101→
102→	var leftParts []string
103→	leftParts = append(leftParts, hashStyle.Render(truncateHash(s.ID)))
104→	timeStr := formatTimeAgo(s.CreatedAt)
105→	if timeStr != "" {
106→		leftParts = append(leftParts, dimStyle.Render(timeStr))
107→	}
108→	if s.Agent != "" {
109→		leftParts = append(leftParts, agentBadgeStyle.Render(truncate(s.Agent, 16)))
110→	}
111→	leftSide := strings.Join(leftParts, sep)
112→
113→	var rightParts []string
114→	if s.Additions > 0 || s.Deletions > 0 {
115→		rightParts = append(rightParts,
116→			addStyle.Render(fmt.Sprintf("+%d", s.Additions))+" / "+
117→				delStyle.Render(fmt.Sprintf("-%d", s.Deletions)))
118→	}
119→	if s.FileCount > 0 {
120→		rightParts = append(rightParts, dimStyle.Render(fmt.Sprintf("%d files", s.FileCount)))
121→	}
122→	if s.SessionCount > 0 {
123→		label := "session"
124→		if s.SessionCount > 1 {
125→			label = "sessions"
126→		}
127→		rightParts = append(rightParts, dimStyle.Render(fmt.Sprintf("%d %s", s.SessionCount, label)))
128→	}
129→	if s.TotalTokens > 0 {
130→		rightParts = append(rightParts, dimStyle.Render(formatTokensShort(s.TotalTokens)))
131→	}
132→	rightSide := strings.Join(rightParts, sep)
133→
134→	metaLine := leftSide
135→	if rightSide != "" {
136→		padding := width - lipgloss.Width(leftSide) - lipgloss.Width(rightSide)
137→		if padding < 2 {
138→			padding = 2
139→		}
140→		metaLine = leftSide + strings.Repeat(" ", padding) + rightSide
141→	}
142→
143→	if subtitle != "" {
144→		return line1 + "\n" + subtitle + "\n" + metaLine
145→	}
146→	return line1 + "\n" + metaLine
147→}
148→
149→func cleanPromptExcerpt(prompt string) string {
150→	if prompt == "" {
151→		return ""
152→	}
153→
154→	prefixes := []string{
155→		"Implement the following plan:",
156→		"implement the following plan:",
157→	}
158→	cleaned := strings.TrimSpace(prompt)
159→	for _, p := range prefixes {
160→		cleaned = strings.TrimPrefix(cleaned, p)
161→	}
162→	cleaned = strings.TrimSpace(cleaned)
163→
164→	for _, line := range strings.SplitN(cleaned, "\n", 20) {
165→		line = strings.TrimSpace(line)
166→		if line == "" || line == "#" || line == "---" {
167→			continue
168→		}
169→		line = strings.TrimLeft(line, "# ")
170→		line = strings.TrimSpace(line)
171→		if line != "" {
172→			return line
173→		}
174→	}
175→	return ""
176→}
177→
178→func filterSummaries(summaries []checkpoint.CheckpointSummary, filter string) []checkpoint.CheckpointSummary {
179→	if filter == "" {
180→		return summaries
181→	}
182→
183→	f := strings.ToLower(filter)
184→	var result []checkpoint.CheckpointSummary
185→	for i := range summaries {
186→		if strings.Contains(strings.ToLower(summaries[i].Branch), f) ||
187→			strings.Contains(strings.ToLower(summaries[i].Agent), f) ||
188→			strings.Contains(strings.ToLower(summaries[i].Prompt), f) ||
189→			strings.Contains(strings.ToLower(summaries[i].Context), f) ||
190→			strings.Contains(strings.ToLower(summaries[i].ID), f) ||
191→			strings.Contains(strings.ToLower(summaries[i].CommitMessage), f) {
192→			result = append(result, summaries[i])
193→		}
194→	}
195→	return result
196→}
197→
198→func formatTimeAgo(t time.Time) string {
199→	if t.IsZero() {
200→		return ""
201→	}
202→	d := time.Since(t)
203→	switch {
204→	case d < time.Minute:
205→		return "just now"
206→	case d < time.Hour:
207→		m := int(d.Minutes())
208→		return fmt.Sprintf("%dm ago", m)
209→	case d < 24*time.Hour:
210→		h := int(d.Hours())
211→		return fmt.Sprintf("%dh ago", h)
212→	default:
213→		days := int(d.Hours() / 24)
214→		return fmt.Sprintf("%dd ago", days)
215→	}
216→}
217→
218→func formatNumber(n int) string {
219→	if n >= 1000 {
220→		return fmt.Sprintf("%d,%03d", n/1000, n%1000)
221→	}
222→	return fmt.Sprintf("%d", n)
223→}
224→
225→func formatTokensShort(n int) string {
226→	if n >= 1000 {
227→		return fmt.Sprintf("%.1fk tokens", float64(n)/1000)
228→	}
229→	return fmt.Sprintf("%d tokens", n)
230→}
231→
232→func truncate(s string, maxLen int) string {
233→	if len(s) <= maxLen {
234→		return s
235→	}
236→	return s[:maxLen-1] + "…"
237→}
238→
239→func truncateHash(hash string) string {
240→	if len(hash) > 7 {
241→		return hash[:7]
242→	}
243→	return hash
244→}
245→

